<?php
// Generated by Cursor prompt — module: Izin (LeaveRequest) — date: 2026-03-15

namespace App\Modules\Izin\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\SoftDeletes;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Support\Facades\DB;

class LeaveRequest extends Model
{
    use SoftDeletes;

    protected $table = 'leave_requests';

    protected $fillable = [
        'company_id',
        'personel_id',
        'leave_type_id',
        'start_date',
        'end_date',
        'total_days',
        'reason',
        'status',
        'workflow',
        'approver_id',
        'approved_at',
        'rejection_reason',
        'attachment_id',
        'created_by',
    ];

    protected $casts = [
        'start_date'  => 'date',
        'end_date'    => 'date',
        'approved_at' => 'datetime',
        'total_days'  => 'decimal:2',
        'workflow'    => 'array',
    ];

    // ─── Durum sabitleri ─────────────────────────────────────────────────────
    const STATUS_PENDING   = 'pending';
    const STATUS_APPROVED  = 'approved';
    const STATUS_REJECTED  = 'rejected';
    const STATUS_CANCELLED = 'cancelled';

    // ─── Relations ───────────────────────────────────────────────────────────

    public function personel(): BelongsTo
    {
        return $this->belongsTo(\App\Modules\Personel\Models\Personel::class);
    }

    public function leaveType(): BelongsTo
    {
        return $this->belongsTo(LeaveType::class);
    }

    public function approver(): BelongsTo
    {
        return $this->belongsTo(\App\Models\User::class, 'approver_id');
    }

    public function createdBy(): BelongsTo
    {
        return $this->belongsTo(\App\Models\User::class, 'created_by');
    }

    // ─── İş Mantığı — Onay Akışı ─────────────────────────────────────────────

    /**
     * Talebi onayla.
     * 1. Bakiye yeterli mi kontrol et.
     * 2. Tatil günleri ile çakışıyor mu?
     * 3. Durum → approved, bakiyeden düş, audit log yaz.
     */
    public function approve(int $approverId, ?string $note = null): array
    {
        if ($this->status !== self::STATUS_PENDING) {
            return ['success' => false, 'message' => 'Bu talep zaten işlenmiş.'];
        }

        // Bakiye kontrolü
        $balance = LeaveBalance::where('personel_id', $this->personel_id)
            ->where('leave_type_id', $this->leave_type_id)
            ->where('year', $this->start_date->year)
            ->first();

        if ($balance && !$balance->hasSufficient($this->total_days)) {
            return ['success' => false, 'message' => "Yetersiz izin bakiyesi. Kalan: {$balance->remaining_days} gün."];
        }

        DB::beginTransaction();
        try {
            // Workflow geçmişine ekle
            $workflow   = $this->workflow ?? [];
            $workflow[] = [
                'step'        => 'approved',
                'user_id'     => $approverId,
                'note'        => $note,
                'timestamp'   => now()->toIso8601String(),
            ];

            $this->update([
                'status'      => self::STATUS_APPROVED,
                'approver_id' => $approverId,
                'approved_at' => now(),
                'workflow'    => $workflow,
            ]);

            // Bakiyeden düş
            $balance?->deduct($this->total_days);

            // Audit log
            DB::table('audit_logs')->insert([
                'user_id'    => $approverId,
                'company_id' => $this->company_id,
                'action'     => 'leave_request.approved',
                'model_type' => LeaveRequest::class,
                'model_id'   => $this->id,
                'changes'    => json_encode(['status' => 'approved', 'days' => $this->total_days]),
                'ip'         => request()->ip(),
                'created_at' => now(),
            ]);

            DB::commit();
            return ['success' => true, 'message' => 'İzin talebi onaylandı.'];

        } catch (\Throwable $e) {
            DB::rollBack();
            return ['success' => false, 'message' => 'Onaylama sırasında hata: ' . $e->getMessage()];
        }
    }

    /**
     * Talebi reddet.
     */
    public function reject(int $rejectorId, string $reason): array
    {
        if ($this->status !== self::STATUS_PENDING) {
            return ['success' => false, 'message' => 'Bu talep zaten işlenmiş.'];
        }

        $workflow   = $this->workflow ?? [];
        $workflow[] = [
            'step'      => 'rejected',
            'user_id'   => $rejectorId,
            'reason'    => $reason,
            'timestamp' => now()->toIso8601String(),
        ];

        $this->update([
            'status'           => self::STATUS_REJECTED,
            'rejection_reason' => $reason,
            'workflow'         => $workflow,
        ]);

        DB::table('audit_logs')->insert([
            'user_id'    => $rejectorId,
            'company_id' => $this->company_id,
            'action'     => 'leave_request.rejected',
            'model_type' => LeaveRequest::class,
            'model_id'   => $this->id,
            'changes'    => json_encode(['status' => 'rejected', 'reason' => $reason]),
            'ip'         => request()->ip(),
            'created_at' => now(),
        ]);

        return ['success' => true, 'message' => 'İzin talebi reddedildi.'];
    }

    /**
     * Talebi iptal et (personel kendi isteği veya yönetici).
     * Onaylı izinler iptal edilirse bakiye iade edilir.
     */
    public function cancel(int $userId, ?string $reason = null): array
    {
        if ($this->status === self::STATUS_CANCELLED) {
            return ['success' => false, 'message' => 'Talep zaten iptal edilmiş.'];
        }

        $wasApproved = $this->status === self::STATUS_APPROVED;

        DB::beginTransaction();
        try {
            $workflow   = $this->workflow ?? [];
            $workflow[] = [
                'step'      => 'cancelled',
                'user_id'   => $userId,
                'reason'    => $reason,
                'timestamp' => now()->toIso8601String(),
            ];

            $this->update([
                'status'   => self::STATUS_CANCELLED,
                'workflow' => $workflow,
            ]);

            // Onaylıysa bakiyeyi iade et
            if ($wasApproved) {
                $balance = LeaveBalance::where('personel_id', $this->personel_id)
                    ->where('leave_type_id', $this->leave_type_id)
                    ->where('year', $this->start_date->year)
                    ->first();
                $balance?->restore($this->total_days);
            }

            DB::table('audit_logs')->insert([
                'user_id'    => $userId,
                'company_id' => $this->company_id,
                'action'     => 'leave_request.cancelled',
                'model_type' => LeaveRequest::class,
                'model_id'   => $this->id,
                'changes'    => json_encode(['was_approved' => $wasApproved]),
                'ip'         => request()->ip(),
                'created_at' => now(),
            ]);

            DB::commit();
            return ['success' => true, 'message' => 'İzin talebi iptal edildi.' . ($wasApproved ? ' Bakiye iade edildi.' : '')];

        } catch (\Throwable $e) {
            DB::rollBack();
            return ['success' => false, 'message' => 'İptal sırasında hata: ' . $e->getMessage()];
        }
    }

    // ─── Yardımcılar ─────────────────────────────────────────────────────────

    /** Çakışan onaylı izin var mı? */
    public function hasOverlap(): bool
    {
        return static::where('personel_id', $this->personel_id)
            ->where('status', self::STATUS_APPROVED)
            ->where('id', '!=', $this->id ?? 0)
            ->where(fn ($q) => $q
                ->whereBetween('start_date', [$this->start_date, $this->end_date])
                ->orWhereBetween('end_date', [$this->start_date, $this->end_date])
                ->orWhere(fn ($q2) => $q2->where('start_date', '<=', $this->start_date)->where('end_date', '>=', $this->end_date))
            )->exists();
    }

    public function getStatusLabelAttribute(): string
    {
        return match ($this->status) {
            'pending'   => 'Bekliyor',
            'approved'  => 'Onaylandı',
            'rejected'  => 'Reddedildi',
            'cancelled' => 'İptal',
            default     => $this->status,
        };
    }

    public function getStatusColorAttribute(): string
    {
        return match ($this->status) {
            'pending'   => 'yellow',
            'approved'  => 'green',
            'rejected'  => 'red',
            'cancelled' => 'gray',
            default     => 'gray',
        };
    }

    // ─── Scopes ──────────────────────────────────────────────────────────────

    public function scopeForCompany($query, int $companyId)
    {
        return $query->where('company_id', $companyId);
    }

    public function scopePending($query)
    {
        return $query->where('status', self::STATUS_PENDING);
    }

    public function scopeApproved($query)
    {
        return $query->where('status', self::STATUS_APPROVED);
    }

    public function scopeForPersonel($query, int $personelId)
    {
        return $query->where('personel_id', $personelId);
    }
}
